import React from 'react';
import Month from '../month/month';
import Day from '../day/day';
import Year from '../year/year';

import './calendar.css';

export default class Calendar extends React.Component {

    render() {

        let content;

        if (this.props.display === 'month') {
            content = <Month date={this.props.date} setCurrentDay={this.props.setCurrentDay} changeMonth ={this.props.changeMonth}/>;
        } else if (this.props.display === 'day') {
            content = <Day number={this.props.currentDayNumber} word={this.props.currentDayWord}/>
        } else if (this.props.display === 'year') {
            content = <Year date={this.props.date}/>
        }
        return (
            <div className="main-obj">
                {content}
            </div>
        )
    }
}