import React from 'react';

import './menu.css';

export default class Menu extends React.Component {

    render() {

        return (
            <div className='menu'>
                <button className='menu-btn' onClick={() => {this.props.changeDisplay('year')}}>Год</button>
                <button className='menu-btn' onClick={() => {this.props.changeDisplay('month')}}>Месяц</button>
                <button className='menu-btn' onClick={() => {this.props.changeDisplay('day')}}>День</button>
            </div>
        )
    }
}