import React from 'react';

import Menu from '../menu/menu';
import Calendar from '../calendar/calendar';

import './app.css';

export default class App extends React.Component {

    constructor(props) {
        super(props);

        this.state = {
            date: new Date(),
            display: 'month',
            currentDayNumber: new Date().getDate(),
            currentDayWord: new Date().getDay(),
        };

        this.setCurrentDay = this.setCurrentDay.bind(this);
        this.changeMonth = this.changeMonth.bind(this);
        this.changeDisplay = this.changeDisplay.bind(this);
    }

    setCurrentDay(number, word) {
        this.setState(() => {
            return {
                display: 'day',
                currentDayNumber: number,
                currentDayWord: word,
            }
        })
    }

    changeDisplay(word) {
        let time = word;
        this.setState(() => {
            return {
                display: time,
            }
        })
    }

    changeMonth(i) {
        let currentDate = this.state.date;
        let newDate = new Date(currentDate.getFullYear(), currentDate.getMonth() + i);

        this.setState(() => {
            return {
                date: newDate,
            }
        })
    }

    render() {

        return (
            <div className='main'>
                <h1>Note Book</h1>
                <Calendar 
                display={this.state.display} 
                date={this.state.date}
                currentDayNumber={this.state.currentDayNumber}
                currentDayWord={this.state.currentDayWord}
                setCurrentDay={this.setCurrentDay}
                changeMonth={this.changeMonth}/>
                <Menu changeDisplay={this.changeDisplay}/>
            </div>
        )
    }
}