import React from 'react';

import './day.css';

export default class Day extends React.Component {

    render() {

        const weekWordsFull = ['воскресенье', 'понедельник', 'вторник', 'среда', 'четверг', 'пятница', 'суббота'];
        return (
            <div className='day'>
                <div className='day-header'>
                    <div className='day-text'>{this.props.number},</div>
                    <div className='day-text'>{weekWordsFull[this.props.word]}</div>
                </div>
                <div className='day-main'>

                </div>
            </div>
        )
    }
}