import React from 'react';

import './month.css';

export default class Month extends React.Component {

    render () {

        let date = this.props.date;
        let dateAll = new Date(date.getFullYear(), date.getMonth());
        let dayFirst = dateAll.getDay();

        const dayWords = ['вс', 'пн', 'вт', 'ср', 'чт', 'пт', 'сб'];
        const monthWords = ['Январь', 'Февраль', 'Март', 'Апрель', 'Май', 'Июнь', 'Июль', 'Август', 'Сентябрь', 'Октябрь', 'Ноябрь', 'Декабрь']

        let daysArr = [];

        let monthLength = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];

        for (let i = 1; i <= monthLength[date.getMonth()]; i++) {
            const day = {
                numberMonth: i,
                numberWeek: dayFirst,
                word: dayWords[dayFirst],
            }
            daysArr.push(day);

            dayFirst++;
            if(dayFirst === 7) {
                dayFirst = 0;
            }
        }

        let color;

        let daysPast = [];
        let daysPresent = [];
        let daysFuture = [];

        for (let i = 0; i < dateAll.getDay() - 1; i++) {
            const day = <div className='days' key={Math.random()}></div>;
            daysPast.push(day);
        }

        for (let i = 0; i < 7 - daysArr[daysArr.length - 1].numberWeek; i++) {
            const day = <div className='days' key={Math.random()}></div>;
            daysFuture.push(day);
        }

        for (let i = 0; i < daysArr.length; i++) {
            if (i + 1 === date.getDate()) {
                color = 'days green';
            } else {
                color = 'days white';
            }

            const day = <div className={color} key={Math.random()} onClick={() => {this.props.setCurrentDay(daysArr[i].numberMonth, daysArr[i].numberWeek)}}>
                    <div className='number'>
                        <div>{daysArr[i].numberMonth}</div>
                        <div>{daysArr[i].word}</div>
                    </div>
            </div>;

            daysPresent.push(day);
        }

        const days = [...daysPast, ...daysPresent, ...daysFuture];

        return (
            <div className="month">
                <div className="month-header">
                    <button className="month-btn left" onClick={() => {this.props.changeMonth(-1)}}>{monthWords[date.getMonth() - 1]}</button>
                    <div className="month-header-text">
                        {monthWords[date.getMonth()]}, {date.getFullYear()}
                    </div>
                    <button className="month-btn right" onClick={() => {this.props.changeMonth(1)}}>{monthWords[date.getMonth() + 1]}</button>
                    </div>
                <div className="month-days">
                    {days}
                </div>
            </div>
        )
    }
}